-- Common types, constants, and utilities shared across all modules
-- 
-- This package provides:
-- - Standard data types for the processor
-- - Control signal definitions
-- - Utility functions
-- - ISA constants

library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

package processor_pkg is

  -- ===== Constants =====
  constant INST_WIDTH : integer := 32;          -- Instruction width in bits
  constant DATA_WIDTH : integer := 32;          -- Data width in bits
  constant IMMEDIATE_WIDTH : integer := 16;     -- Immediate width in bits
  constant ADDR_WIDTH : integer := 32;          -- Address width in bits
  constant REG_ADDR_WIDTH : integer := 5;       -- Register address width
  constant OPCODE_WIDTH : integer := 9;         -- OPCODE field width

  constant MEMORY_DEPTH : integer := 1024;      -- Memory depth (words) TODO: Adjust FROM MEMORY
  constant MEMORY_SIZE : integer := MEMORY_DEPTH * (DATA_WIDTH / 8);  -- Memory size in bytes TODO: Adjust FROM MEMORY

  -- ===== Opcodes =====
  constant OP_NOP    : std_logic_vector(OPCODE_WIDTH - 1 downto 0) := "000000000";

  -- ===== ALU Operations =====
  constant ALU_NOP  : std_logic_vector(3 downto 0) := "0000";

  -- ===== Types =====

  -- Instruction format type
  type instruction_t is record
    opcode : std_logic_vector(OPCODE_WIDTH - 1 downto 0);
    rd     : std_logic_vector(REG_ADDR_WIDTH - 1 downto 0);
    rs1    : std_logic_vector(REG_ADDR_WIDTH - 1 downto 0);
    rs2    : std_logic_vector(REG_ADDR_WIDTH - 1 downto 0);
    imm    : std_logic_vector(IMMEDIATE_WIDTH - 1 downto 0);
  end record instruction_t;

  -- Pipeline control signals
  type control_signals_t is record
  end record control_signals_t;

  -- ===== Utility Functions =====

  -- Extract instruction fields
  function get_opcode(inst : std_logic_vector(INST_WIDTH - 1 downto 0))
    return std_logic_vector;

  function get_rd(inst : std_logic_vector(INST_WIDTH - 1 downto 0))
    return std_logic_vector;


  function get_rs1(inst : std_logic_vector(INST_WIDTH - 1 downto 0))
    return std_logic_vector;

  function get_rs2(inst : std_logic_vector(INST_WIDTH - 1 downto 0))
    return std_logic_vector;


  -- Extract I-type immediate
  function get_imm_i(inst : std_logic_vector(INST_WIDTH - 1 downto 0))
    return std_logic_vector;

end package processor_pkg;

package body processor_pkg is

  function get_opcode(inst : std_logic_vector(INST_WIDTH - 1 downto 0))
    return std_logic_vector is
  begin
    return inst(8 downto 0);
  end function get_opcode;

  function get_rd(inst : std_logic_vector(INST_WIDTH - 1 downto 0))
    return std_logic_vector is
  begin
    return inst(13 downto 9);
  end function get_rd;

  function get_rs1(inst : std_logic_vector(INST_WIDTH - 1 downto 0))
    return std_logic_vector is
  begin
    return inst(18 downto 14);
  end function get_rs1;

  function get_rs2(inst : std_logic_vector(INST_WIDTH - 1 downto 0))
    return std_logic_vector is
  begin
    return inst(23 downto 19);
  end function get_rs2;

  function get_imm_i(inst : std_logic_vector(INST_WIDTH - 1 downto 0))
    return std_logic_vector is
    variable imm : std_logic_vector(15 downto 0);
  begin
    imm := inst(31 downto 16);
    return imm; // TODO: Sign-extend if NEEDED
  end function get_imm_i;

end package body processor_pkg;

